Advisory/Declarations/NonFinalImmutableF:
/**
 * @name Non-final immutable field
 * @description A field of immutable type that is assigned to only in a constructor or static
 *              initializer of its declaring type, but is not declared 'final', may lead to defects
 *              and makes code less readable.
 * @kind problem
 * @problem.severity recommendation
 * @precision medium
 * @id java/non-final-immutable-field
 * @tags quality
 *       reliability
 *       correctness
 *       readability
 */

import java

class Initialization extends Callable {
  Initialization() {
    this instanceof Constructor or
    this instanceof InitializerMethod
  }
}

/** A binary or unary assignment. */
class AnyAssignment extends Expr {
  AnyAssignment() {
    this instanceof Assignment or
    this instanceof UnaryAssignExpr
  }

  /** The expression modified by this assignment. */
  Expr getDest() {
    this.(Assignment).getDest() = result or
    this.(UnaryAssignExpr).getExpr() = result
  }
}

class ImmutableField extends Field {
  ImmutableField() {
    this.fromSource() and
    not this instanceof EnumConstant and
    this.getType() instanceof ImmutableType and
    // The field is only assigned to in a constructor or static initializer of the type it is declared in.
    forall(FieldAccess fw, AnyAssignment ae |
      fw.getField() = this and
      fw = ae.getDest()
    |
      ae.getEnclosingCallable().getDeclaringType() = this.getDeclaringType() and
      ae.getEnclosingCallable() instanceof Initialization
    )
  }
}

from ImmutableField f
where not f.isFinal()
select f,
  "This immutable field is not declared final but is only assigned to during initialization."

Architecture/Dependencies/UnusedMavenDep:
/**
 * @name Unused Maven dependency (source)
 * @description Unnecessary Maven dependencies are a maintenance burden.
 * @kind problem
 * @problem.severity recommendation
 * @precision low
 * @id java/unused-maven-source-dependency
 */

import java
import semmle.code.xml.MavenPom
import UnusedMavenDependencies

from PomDependency d, Pom source, Pom target
where
  source.getADependency() = d and
  // We have a targetPom file, so this is a "source" dependency, rather than a binary dependency
  // from the Maven repository. Note, although .pom files exist in the local maven repository, they
  // are usually not indexed because they are outside the source directory. We assume that they have
  // not been indexed.
  target = d.getPom() and
  // If we have a pom for the target of this dependency, then it is unused iff neither it, nor any
  // of its transitive dependencies are required.
  not exists(Pom exported | exported = target.getAnExportedPom*() |
    pomDependsOnContainer(source, exported.getAnExportedDependency().getJar()) or
    pomDependsOnPom(source, exported)
  )
select d, "Maven dependency onto " + d.getShortCoordinate() + " is unused."

/**
 * @name Unused Maven dependency (binary)
 * @description Unnecessary Maven dependencies are a maintenance burden.
 * @kind problem
 * @problem.severity recommendation
 * @precision low
 * @id java/unused-maven-binary-dependency
 */

import UnusedMavenDependencies

/**
 * A whitelist of binary dependencies that should never be highlighted as unusued.
 */
predicate whitelist(Dependency d) {
  // jsr305 contains package annotations. If a project uses those exclusively, we will
  // consider it "unused".
  d.getShortCoordinate() = "com.google.code.findbugs:jsr305"
}

from PomDependency d, Pom source
where
  source.getADependency() = d and
  // There is not a Pom file for the target of this dependency, so we assume that it was resolved by
  // a binary file in the local maven repository.
  not exists(d.getPom()) and
  // In order to accurately identify whether this binary dependency is required, we must have identified
  // a Maven repository. If we have not found a repository, it's likely that it has a custom path of
  // which we are unaware, so do not report any problems.
  exists(MavenRepo mr) and
  // We either haven't indexed a relevant jar file, which suggests that nothing statically depended upon
  // it, or we have indexed the relevant jar file, but no source code in the project defined by the pom
  // depends on any code within the detected jar.
  not pomDependsOnContainer(source, d.getJar()) and
  // If something that depends on us depends on the jar represented by this dependency, and it doesn't
  // depend directly on the jar itself, we don't consider it to be "unused".
  not exists(Pom pomThatDependsOnSource | pomThatDependsOnSource.getAnExportedPom+() = source |
    pomDependsOnContainer(pomThatDependsOnSource, d.getJar()) and
    not exists(File f | f = pomThatDependsOnSource.getADependency().getJar() and f = d.getJar())
  ) and
  // Filter out those dependencies on the whitelist
  not whitelist(d)
select d, "Maven dependency on the binary package " + d.getShortCoordinate() + " is unused."

Architecture/Refactoring Opportunities/F:
/**
 * @name Feature envy
 * @description A method that uses more methods or variables from another (unrelated) class than
 *              from its own class violates the principle of putting data and behavior in the same
 *              place.
 * @kind problem
 * @problem.severity warning
 * @precision low
 * @id java/feature-envy
 * @tags maintainability
 *       modularity
 */

import java

Member getAUsedMember(Method m) {
  result.(Field).getAnAccess().getEnclosingCallable() = m or
  result.(Callable).getAReference().getEnclosingCallable() = m
}

int dependencyCount(Method source, RefType target) {
  result = strictcount(Member m | m = getAUsedMember(source) and m = target.getAMember())
}

predicate methodDependsOn(Method m, RefType target) { exists(dependencyCount(m, target)) }

predicate dependsOn(RefType source, RefType target) {
  methodDependsOn(source.getACallable(), target)
}

int selfDependencyCount(Method source) {
  result = sum(dependencyCount(source, source.getDeclaringType().getEnclosingType*()))
}

predicate dependsHighlyOn(Method source, RefType target, int selfCount, int depCount) {
  depCount = dependencyCount(source, target) and
  selfCount = selfDependencyCount(source) and
  depCount > 2 * selfCount and
  depCount > 4
}

predicate query(Method m, RefType targetType, int selfCount, int depCount) {
  exists(RefType sourceType | sourceType = m.getDeclaringType() |
    dependsHighlyOn(m, targetType, selfCount, depCount) and
    // Interfaces are depended upon by their very nature
    not targetType instanceof Interface and
    // Anonymous classes are often used as callbacks, which heavily depend on other classes
    not sourceType instanceof AnonymousClass and
    // Do not move initializer methods
    not m instanceof InitializerMethod and
    // Do not move up/down the class hierarchy
    not (
      sourceType.getAnAncestor().getSourceDeclaration() = targetType or
      targetType.getAnAncestor().getSourceDeclaration() = sourceType
    ) and
    // Do not move between nested types
    not (sourceType.getEnclosingType*() = targetType or targetType.getEnclosingType*() = sourceType) and
    // Tests are allowed to be invasive and depend on the tested classes highly
    not sourceType instanceof TestClass and
    // Check that the target type already depends on every type used by the method
    forall(RefType dependency | methodDependsOn(m, dependency) | dependsOn(targetType, dependency))
  )
}

from Method m, RefType other, int selfCount, int depCount
where
  query(m, other, selfCount, depCount) and
  // Don't include types that are used from many different places - we only highlight
  // relatively local fixes that could reasonably be implemented.
  count(Method yetAnotherMethod | query(yetAnotherMethod, other, _, _)) < 10
select m,
  "Method " + m.getName() + " is too closely tied to $@: " + depCount +
    " dependencies to it, but only " + selfCount + " dependencies to its own type.", other,
  other.getName()

Compatibility/JDK9/JdkInternalAccess.ql:
/**
 * @name Access to unsupported JDK-internal API
 * @description Use of unsupported JDK-internal APIs may cause compatibility issues
 *              when upgrading to newer versions of Java, in particular Java 9.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id java/jdk-internal-api-access
 * @tags quality
 *       maintainability
 *       readability
 */

import java
import JdkInternals
import JdkInternalsReplacement

predicate importedType(Import i, RefType t) {
  i.(ImportType).getImportedType() = t or
  i.(ImportStaticTypeMember).getTypeHoldingImport() = t or
  i.(ImportStaticOnDemand).getTypeHoldingImport() = t or
  i.(ImportOnDemandFromType).getTypeHoldingImport() = t
}

predicate importedPackage(Import i, Package p) {
  i.(ImportOnDemandFromPackage).getPackageHoldingImport() = p
}

predicate typeReplacement(RefType t, string repl) {
  exists(string old | jdkInternalReplacement(old, repl) | t.getQualifiedName() = old)
}

predicate packageReplacementForType(RefType t, string repl) {
  exists(string old, string pkgName |
    jdkInternalReplacement(old, repl) and t.getPackage().getName() = pkgName
  |
    pkgName = old or
    pkgName.prefix(old.length() + 1) = old + "."
  )
}

predicate packageReplacement(Package p, string repl) {
  exists(string old | jdkInternalReplacement(old, repl) |
    p.getName() = old or
    p.getName().prefix(old.length() + 1) = old + "."
  )
}

predicate replacement(RefType t, string repl) {
  typeReplacement(t, repl)
  or
  not typeReplacement(t, _) and packageReplacementForType(t, repl)
}

abstract class JdkInternalAccess extends Element {
  abstract string getAccessedApi();

  abstract string getReplacement();
}

class JdkInternalTypeAccess extends JdkInternalAccess, TypeAccess {
  JdkInternalTypeAccess() { jdkInternalApi(this.getType().(RefType).getPackage().getName()) }

  override string getAccessedApi() { result = this.getType().(RefType).getQualifiedName() }

  override string getReplacement() {
    exists(RefType t | this.getType() = t |
      (
        replacement(t, result)
        or
        not replacement(t, _) and result = "unknown"
      )
    )
  }
}

class JdkInternalImport extends JdkInternalAccess, Import {
  JdkInternalImport() {
    exists(RefType t | importedType(this, t) | jdkInternalApi(t.getPackage().getName()))
    or
    exists(Package p | importedPackage(this, p) | jdkInternalApi(p.getName()))
  }

  override string getAccessedApi() {
    exists(RefType t | result = t.getQualifiedName() | importedType(this, t))
    or
    exists(Package p | result = p.getName() | importedPackage(this, p))
  }

  override string getReplacement() {
    exists(RefType t |
      importedType(this, t) and
      (
        replacement(t, result)
        or
        not replacement(t, _) and result = "unknown"
      )
    )
    or
    exists(Package p |
      importedPackage(this, p) and
      (
        packageReplacement(p, result)
        or
        not packageReplacement(p, _) and result = "unknown"
      )
    )
  }
}

predicate jdkPackage(Package p) {
  exists(string pkgName |
    p.getName() = pkgName or
    p.getName().prefix(pkgName.length() + 1) = pkgName + "."
  |
    pkgName =
      [
        "com.sun", "sun", "java", "javax", "com.oracle.net", "genstubs", "jdk", "build.tools",
        "org.omg.CORBA", "org.ietf.jgss"
      ]
  )
}

from JdkInternalAccess ta, string repl, string msg
where
  repl = ta.getReplacement() and
  (if repl = "unknown" then msg = "" else msg = " (" + repl + ")") and
  not jdkInternalApi(ta.getCompilationUnit().getPackage().getName()) and
  not jdkPackage(ta.getCompilationUnit().getPackage())
select ta, "Access to unsupported JDK-internal API '" + ta.getAccessedApi() + "'." + msg

Frameworks/Spring/Violations of Best Pra:
/**
 * @name Use shortcut forms for values
 * @description Using shortcut forms may make a Spring XML configuration file less cluttered.
 * @kind problem
 * @problem.severity recommendation
 * @precision low
 * @id java/spring/non-shortcut-form
 * @tags maintainability
 *       frameworks/spring
 */

import java
import semmle.code.java.frameworks.spring.Spring

class SpringConstructorArgUseShortcut extends SpringConstructorArg {
  SpringConstructorArgUseShortcut() {
    not this.hasArgValueString() and
    this.getASpringChild() instanceof SpringValue
  }

  string getMessage() {
    not this.hasArgValueString() and
    this.getASpringChild() instanceof SpringValue and
    result = "Use the shortcut \"value\" attribute instead of a nested <value> element."
  }
}

class SpringEntryUseShortcut extends SpringEntry {
  SpringEntryUseShortcut() {
    not this.hasValueStringRaw() and
    this.getASpringChild() instanceof SpringValue
  }

  string getMessage() {
    not this.hasValueStringRaw() and
    this.getASpringChild() instanceof SpringValue and
    result = "Use the shortcut \"value\" attribute instead of a nested <value> element."
  }
}

class SpringPropertyUseShortcut extends SpringProperty {
  SpringPropertyUseShortcut() {
    not this.hasPropertyValueString() and
    this.getASpringChild() instanceof SpringValue
  }

  string getMessage() {
    not this.hasPropertyValueString() and
    this.getASpringChild() instanceof SpringValue and
    result = "Use the shortcut \"value\" attribute instead of a nested <value> element."
  }
}

from SpringXmlElement springElement, string msg
where
  exists(SpringConstructorArgUseShortcut cons | cons = springElement and msg = cons.getMessage())
  or
  exists(SpringEntryUseShortcut entry | entry = springElement and msg = entry.getMessage())
  or
  exists(SpringPropertyUseShortcut prop | prop = springElement and msg = prop.getMessage())
select springElement, msg

Frameworks/Spring/Architecture/Refactori:
/**
 * @name Beans that are never used within the code
 * @description Beans that are specified but never used are redundant and should be removed.
 * @kind problem
 * @problem.severity recommendation
 * @precision low
 * @id java/spring/unused-bean
 * @tags maintainability
 *       frameworks/spring
 */

import java
import semmle.code.java.frameworks.spring.Spring

/**
 * A `FieldWrite` that writes to the same instance as the enclosing callable.
 */
class InstanceFieldWrite extends FieldWrite {
  InstanceFieldWrite() {
    // Must be in an instance callable
    not this.getEnclosingCallable().isStatic() and
    // Must be declared in this type or a supertype.
    this.getEnclosingCallable().getDeclaringType().inherits(this.getField()) and
    this.isOwnFieldAccess()
  }
}

/**
 * A conservative approximation of statements that may affect state outside the context of the current
 * class.
 */
class ImpureStmt extends Stmt {
  ImpureStmt() {
    exists(Expr e | e.getEnclosingStmt() = this |
      // Only permit calls to set of whitelisted targets.
      e instanceof Call and
      not e.(Call).getCallee().getDeclaringType().hasQualifiedName("java.util", "Collections")
      or
      // Writing to a field that is not an instance field is a no-no
      e instanceof FieldWrite and not e instanceof InstanceFieldWrite
    )
  }
}

/**
 * Get any non-block stmt in the block, including those nested within blocks.
 */
private Stmt getANestedStmt(BlockStmt block) {
  // Any non-block statement
  not result instanceof BlockStmt and result = block.getAStmt()
  or
  // Or any statement nested in a block
  result = getANestedStmt(block.getAStmt())
}

/**
 * A class whose loading and construction by Spring does not have any side-effects outside the class.
 *
 * This is a conservative approximation.
 */
class SpringPureClass extends Class {
  SpringPureClass() {
    // The only permitted statement in static initializers is the initialization of a static
    // final or effectively final logger fields, or effectively immutable types.
    forall(Stmt s | s = getANestedStmt(this.getAMember().(StaticInitializer).getBody()) |
      exists(Field f | f = s.(ExprStmt).getExpr().(AssignExpr).getDest().(FieldWrite).getField() |
        (
          // A logger field
          f.getName().toLowerCase() = "logger" or
          f.getName().toLowerCase() = "log" or
          // An immutable type
          f.getType() instanceof ImmutableType
        ) and
        f.isStatic() and
        // Only written to in this statement e.g. final or effectively final
        forall(FieldWrite fw | fw = f.getAnAccess() | fw.getEnclosingStmt() = s)
      )
    ) and
    // No constructor, instance initializer or Spring bean init or setter method that is impure.
    not exists(Callable c, ImpureStmt impureStmt |
      (
        this.inherits(c.(Method)) or
        c = this.getAMember()
      ) and
      impureStmt.getEnclosingCallable() = c
    |
      c instanceof InstanceInitializer
      or
      c instanceof Constructor
      or
      // afterPropertiesSet() method called after bean initialization
      c = this.(InitializingBeanClass).getAfterPropertiesSet()
      or
      // Init and setter methods must be pure, because they are called when the bean is initialized
      exists(SpringBean bean | this = bean.getClass() |
        c = bean.getInitMethod() or
        c = bean.getAProperty().getSetterMethod()
      )
      or
      // Setter method by autowiring, either in the XML or by annotation
      c = this.getAMethod().(SpringBeanAutowiredCallable)
      or
      c = this.getAMethod().(SpringBeanXmlAutowiredSetterMethod)
    )
  }
}

/**
 * A Spring class the constructs beans based on the bean identifier.
 */
class SpringBeanFactory extends ClassOrInterface {
  SpringBeanFactory() {
    this.getAnAncestor().hasQualifiedName("org.springframework.beans.factory", "BeanFactory")
  }

  /**
   * Get a bean constructed by a call to this bean factory.
   */
  SpringBean getAConstructedBean() {
    exists(Method getBean, MethodCall call |
      getBean.hasName("getBean") and
      call.getMethod() = getBean and
      getBean.getDeclaringType() = this
    |
      result.getBeanIdentifier() = call.getArgument(0).(CompileTimeConstantExpr).getStringValue()
    )
  }
}

/**
 * A `SpringBean` which is meaningfully used within the program.
 *
 * A meaningfully used bean cannot be removed without changing the observable behavior of the program.
 */
class LiveSpringBean extends SpringBean {
  LiveSpringBean() {
    // Must not be needed for side effects due to construction
    // Only loaded by the container when required, so construction cannot have any useful side-effects
    not this.isLazyInit() and
    // or has no side-effects when constructed
    not this.getClass() instanceof SpringPureClass
    or
    (
      // If the class does not exist for this bean, or the class is not a source bean, then this is
      // likely to be a definition using a library class, in which case we should consider it to be
      // live.
      not exists(this.getClass())
      or
      not this.getClass().fromSource()
      or
      // In alfresco, "webscript" beans should be considered live
      this.getBeanParent*().getBeanParentName() = "webscript"
      or
      // A live child bean implies this bean is live
      exists(LiveSpringBean child | this = child.getBeanParent())
      or
      // Beans constructed by a bean factory are considered live
      exists(SpringBeanFactory beanFactory | this = beanFactory.getAConstructedBean())
    )
    or
    (
      // Referenced by a live bean, either as a property or argument in the XML
      exists(LiveSpringBean other |
        this = other.getAConstructorArg().getArgRefBean() or
        this = other.getAProperty().getPropertyRefBean()
      )
      or
      // Referenced as a factory bean
      exists(LiveSpringBean springBean | this = springBean.getFactoryBean())
      or
      // Injected by @Autowired annotation
      exists(SpringBeanAutowiredCallable autowiredCallable |
        // The callable must be in a live class
        autowiredCallable.getEnclosingSpringBean() instanceof LiveSpringBean or
        autowiredCallable.getEnclosingSpringComponent().isLive()
      |
        // This bean is injected into it
        this = autowiredCallable.getAnInjectedBean()
      )
      or
      // Injected by @Autowired annotation on field
      exists(SpringBeanAutowiredField autowiredField |
        // The field must be in a live class
        autowiredField.getEnclosingSpringBean() instanceof LiveSpringBean or
        autowiredField.getEnclosingSpringComponent().isLive()
      |
        // This bean is injected into it
        this = autowiredField.getInjectedBean()
      )
      or
      // Injected by autowired specified in XML
      exists(SpringBeanXmlAutowiredSetterMethod setterMethod |
        // The config method must be on a live bean
        setterMethod.getDeclaringType().(SpringBeanRefType).getSpringBean() instanceof
          LiveSpringBean
      |
        // This bean is injected into it
        this = setterMethod.getInjectedBean()
      )
    )
  }
}

/**
 * A `SpringBean` that can be safely removed from the program without changing overall behavior.
 */
class UnusedSpringBean extends SpringBean {
  UnusedSpringBean() { not this instanceof LiveSpringBean }
}

from UnusedSpringBean unused
select unused, "The spring bean " + unused.getBeanIdentifier() + " is never used."

Language Abuse/IterableIterator.ql:
/**
 * @name Iterator implementing Iterable
 * @description An 'Iterator' that also implements 'Iterable' by returning itself as its 'Iterator'
 *              does not support multiple traversals. This can lead to unexpected behavior when
 *              it is viewed as an 'Iterable'.
 * @kind problem
 * @problem.severity warning
 * @precision very-high
 * @id java/iterator-implements-iterable
 * @tags quality
 *       reliability
 *       correctness
 */

import java
import IterableClass

/** An `Iterable` that is also its own `Iterator`. */
class IterableIterator extends Iterable {
  IterableIterator() { this.simpleIterator() instanceof ThisAccess }
}

/** An `IterableIterator` that never returns any elements. */
class EmptyIterableIterator extends IterableIterator {
  EmptyIterableIterator() {
    exists(Method m |
      m.getDeclaringType().getSourceDeclaration() = this and
      m.getName() = "hasNext" and
      m.getBody()
          .(SingletonBlock)
          .getStmt()
          .(ReturnStmt)
          .getResult()
          .(BooleanLiteral)
          .getBooleanValue() = false
    )
  }
}

from IterableIterator i
where
  // Exclude the empty iterator as that is safe to reuse.
  not i instanceof EmptyIterableIterator
select i, "This Iterable is its own Iterator, but does not guard against multiple iterations."

Likely Bugs/Serialization/NonSerializabl:
/**
 * @name Non-serializable field
 * @description A non-transient field in a serializable class must also be serializable
 *              otherwise it causes the class to fail to serialize with a 'NotSerializableException'.
 * @kind problem
 * @problem.severity warning
 * @precision low
 * @id java/non-serializable-field
 * @tags reliability
 *       maintainability
 *       language-features
 */

import java
import semmle.code.java.Collections
import semmle.code.java.Maps
import semmle.code.java.frameworks.javaee.ejb.EJB

predicate externalizable(Interface interface) {
  interface.hasQualifiedName("java.io", "Externalizable")
}

predicate serializableOrExternalizable(Interface interface) {
  externalizable(interface) or
  interface instanceof TypeSerializable
}

predicate collectionOrMapType(RefType t) { t instanceof CollectionType or t instanceof MapType }

predicate serializableType(RefType t) {
  exists(RefType sup | sup = t.getAnAncestor() | serializableOrExternalizable(sup))
  or
  // Collection interfaces are not serializable, but their implementations are
  // likely to be.
  collectionOrMapType(t) and
  not t instanceof RawType and
  forall(RefType param | param = t.(ParameterizedType).getATypeArgument() | serializableType(param))
  or
  exists(BoundedType bt | bt = t | serializableType(bt.getUpperBoundType()))
}

RefType reasonForNonSerializableCollection(ParameterizedType par) {
  collectionOrMapType(par) and
  result = par.getATypeArgument() and
  not serializableType(result)
}

string nonSerialReason(RefType t) {
  not serializableType(t) and
  if exists(reasonForNonSerializableCollection(t))
  then result = reasonForNonSerializableCollection(t).getName() + " is not serializable"
  else result = t.getName() + " is not serializable"
}

predicate exceptions(Class c, Field f) {
  f.getDeclaringType() = c and
  (
    c.isCompilerGenerated()
    or
    // `Serializable` objects with custom `readObject` or `writeObject` methods
    // may write out the "non-serializable" fields in a different way.
    c.declaresMethod("readObject")
    or
    c.declaresMethod("writeObject")
    or
    // Exclude classes with suppressed warnings.
    c.suppressesWarningsAbout("serial")
    or
    // Exclude anonymous classes whose `ClassInstanceExpr` is assigned to
    // a variable on which serialization warnings are suppressed.
    exists(Variable v |
      v.getAnAssignedValue() = c.(AnonymousClass).getClassInstanceExpr() and
      v.suppressesWarningsAbout("serial")
    )
    or
    f.isTransient()
    or
    f.isStatic()
    or
    // Classes that implement `Externalizable` completely take over control during serialization.
    externalizable(c.getAStrictAncestor())
    or
    // Stateless session beans are not normally serialized during their usual life-cycle
    // but are forced by their expected supertype to be serializable.
    // Arguably, warnings for their non-serializable fields can therefore be suppressed in practice.
    c instanceof StatelessSessionEjb
    or
    // Enum types are serialized by name, so it doesn't matter if they have non-serializable fields.
    c instanceof EnumType
  )
}

from Class c, Field f, string reason
where
  c.fromSource() and
  c.getAStrictAncestor() instanceof TypeSerializable and
  f.getDeclaringType() = c and
  not exceptions(c, f) and
  reason = nonSerialReason(f.getType())
select f,
  "This field is in a serializable class, but is not serializable itself because " + reason + "."

Likely Bugs/Concurrency/UnreleasedLock.q:
/**
 * @name Unreleased lock
 * @description A lock that is acquired one or more times without a matching number of unlocks
 *              may cause a deadlock.
 * @kind problem
 * @problem.severity error
 * @security-severity 5.0
 * @precision medium
 * @id java/unreleased-lock
 * @tags reliability
 *       security
 *       external/cwe/cwe-764
 *       external/cwe/cwe-833
 */

import java
import semmle.code.java.controlflow.Guards
import semmle.code.java.dataflow.SSA
import semmle.code.java.Concurrency

predicate lockBlock(LockType t, BasicBlock b, int locks) {
  locks = strictcount(int i | b.getNode(i).asExpr() = t.getLockAccess())
}

predicate unlockBlock(LockType t, BasicBlock b, int unlocks) {
  unlocks = strictcount(int i | b.getNode(i).asExpr() = t.getUnlockAccess())
}

/**
 * A block `b` that locks and/or unlocks `t` a number of times; `netlocks`
 * equals the number of locks minus the number of unlocks.
 */
predicate lockUnlockBlock(LockType t, BasicBlock b, int netlocks) {
  lockBlock(t, b, netlocks) and not unlockBlock(t, b, _)
  or
  exists(int unlocks |
    not lockBlock(t, b, _) and unlockBlock(t, b, unlocks) and netlocks = -unlocks
  )
  or
  exists(int locks, int unlocks |
    lockBlock(t, b, locks) and unlockBlock(t, b, unlocks) and netlocks = locks - unlocks
  )
}

/**
 * A call to `lock` or `tryLock` on `t` that fails with an exception or the value `false`
 * resulting in a CFG edge from `lockblock` to `exblock`.
 */
predicate failedLock(LockType t, BasicBlock lockblock, BasicBlock exblock) {
  exists(ControlFlowNode lock |
    lock = lockblock.getLastNode() and
    (
      lock.asExpr() = t.getLockAccess()
      or
      exists(SsaExplicitWrite lockbool |
        // Using the value of `t.getLockAccess()` ensures that it is a `tryLock` call.
        lock.asExpr() = lockbool.getARead() and
        lockbool.getValue() = t.getLockAccess()
      )
    ) and
    (
      lock.getAnExceptionSuccessor() = exblock.getFirstNode() or
      lock.(ConditionNode).getAFalseSuccessor() = exblock.getFirstNode()
    )
  )
}

/**
 * A call to `isHeldByCurrentThread` on `t` in `checkblock` that has `falsesucc` as the false
 * successor.
 */
predicate heldByCurrentThreadCheck(LockType t, BasicBlock checkblock, BasicBlock falsesucc) {
  exists(ConditionBlock conditionBlock |
    conditionBlock.getCondition() = t.getIsHeldByCurrentThreadAccess()
  |
    conditionBlock = checkblock and
    conditionBlock.getTestSuccessor(false) = falsesucc
  )
}

/**
 * Holds if there is a variable access in `checkblock` that has `falsesucc` as the false successor.
 *
 * The variable access must have an assigned value that is a lock access on `t`, and
 * the true successor of `checkblock` must contain an unlock access.
 */
predicate variableLockStateCheck(LockType t, BasicBlock checkblock, BasicBlock falsesucc) {
  exists(ConditionBlock conditionBlock, VarAccess v |
    v.getType() instanceof BooleanType and
    // Ensure that a lock access is assigned to the variable
    v.getVariable().getAnAssignedValue() = t.getLockAccess() and
    // Ensure that the `true` successor of the condition block contains an unlock access
    conditionBlock.getTestSuccessor(true) = t.getUnlockAccess().getBasicBlock() and
    conditionBlock.getCondition() = v
  |
    conditionBlock = checkblock and
    conditionBlock.getTestSuccessor(false) = falsesucc
  )
}

/**
 * A control flow path from a locking call in `src` to `b` such that the number of
 * locks minus the number of unlocks along the way is positive and equal to `locks`.
 */
predicate blockIsLocked(LockType t, BasicBlock src, BasicBlock b, int locks) {
  lockUnlockBlock(t, b, locks) and src = b and locks > 0
  or
  exists(BasicBlock pred, int predlocks, int curlocks, int failedlock | pred = b.getAPredecessor() |
    // The number of net locks from the `src` block to the predecessor block `pred` is `predlocks`.
    blockIsLocked(t, src, pred, predlocks) and
    // The recursive call ensures that at least one lock is held, so do not consider the false
    // successor of the `isHeldByCurrentThread()` check or of `variableLockStateCheck`.
    not heldByCurrentThreadCheck(t, pred, b) and
    not variableLockStateCheck(t, pred, b) and
    // Count a failed lock as an unlock so the net is zero.
    (if failedLock(t, pred, b) then failedlock = 1 else failedlock = 0) and
    (
      not lockUnlockBlock(t, b, _) and curlocks = 0
      or
      lockUnlockBlock(t, b, curlocks)
    ) and
    locks = predlocks + curlocks - failedlock and
    locks > 0 and
    // Arbitrary bound in order to fail gracefully in case of locking in a loop.
    locks < 10
  )
}

from Callable c, LockType t, BasicBlock src, ExitBlock exit, MethodCall lock
where
  // Restrict results to those methods that actually attempt to unlock.
  t.getUnlockAccess().getEnclosingCallable() = c and
  blockIsLocked(t, src, exit, _) and
  exit.getEnclosingCallable() = c and
  lock = src.getANode().asExpr() and
  lock = t.getLockAccess()
select lock, "This lock might not be unlocked or might be locked more times than it is unlocked."

Likely Bugs/Concurrency/LazyInitStaticFi:
/**
 * @name Incorrect lazy initialization of a static field
 * @description Initializing a static field without synchronization can be problematic
 *              in a multi-threaded context.
 * @kind problem
 * @problem.severity warning
 * @precision low
 * @id java/lazy-initialization
 * @tags reliability
 *       correctness
 *       concurrency
 *       external/cwe/cwe-543
 *       external/cwe/cwe-609
 */

import java

/** A comparison (using `==`) with `null`. */
class NullEQExpr extends ValueOrReferenceEqualsExpr {
  NullEQExpr() { exists(NullLiteral l | l.getParent() = this) }
}

/** An assignment to a static field. */
class StaticFieldInit extends AssignExpr {
  StaticFieldInit() { exists(Field f | f.isStatic() | f.getAnAccess() = this.getDest()) }

  Field getField() { result.getAnAccess() = this.getDest() }

  IfStmt getAnEnclosingNullCheck() {
    result.getThen().getAChild*() = this.getEnclosingStmt() and
    result.getCondition().(NullEQExpr).getAChildExpr() = this.getField().getAnAccess()
  }

  IfStmt getNearestNullCheck() {
    result = this.getAnEnclosingNullCheck() and
    not result.getAChild+() = this.getAnEnclosingNullCheck()
  }
}

/** A field that is a candidate for a "lock object". */
class LockObjectField extends Field {
  LockObjectField() {
    this.isStatic() and
    forex(Callable init | init = this.getAnAssignedValue().getEnclosingCallable() |
      init instanceof StaticInitializer
    )
  }
}

/** A synchronized statement on a class literal. */
class ValidSynchStmt extends Stmt {
  ValidSynchStmt() {
    // It's OK to lock the enclosing class.
    this.(SynchronizedStmt).getExpr().(TypeLiteral).getReferencedType() =
      this.getEnclosingCallable().getDeclaringType()
    or
    // It's OK to lock on a "lock object field".
    this.(SynchronizedStmt).getExpr().(FieldRead).getField() instanceof LockObjectField
    or
    // Locking via `ReentrantLock` lock object instead of synchronized statement.
    exists(TryStmt try, LockObjectField lockField |
      this = try.getBlock() and
      lockField.getType().(RefType).hasQualifiedName("java.util.concurrent.locks", "ReentrantLock") and
      exists(MethodCall lockAction |
        lockAction.getQualifier() = lockField.getAnAccess() and
        lockAction.getMethod().getName() = "lock" and
        dominates(lockAction.getControlFlowNode(), this.getControlFlowNode())
      ) and
      exists(MethodCall unlockAction |
        unlockAction.getQualifier() = lockField.getAnAccess() and
        unlockAction.getMethod().getName() = "unlock" and
        postDominates(unlockAction.getControlFlowNode(), this.getControlFlowNode())
      )
    )
  }
}

/** A static method. */
class StaticMethod extends Method {
  StaticMethod() { this.isStatic() }

  predicate bodyIsSynchronized() {
    this.isSynchronized() or
    this.getBody().getAChild() instanceof ValidSynchStmt
  }
}

from StaticMethod method, IfStmt i, StaticFieldInit init, string message
where
  i = init.getNearestNullCheck() and
  method = i.getEnclosingCallable() and
  not method.bodyIsSynchronized() and
  not method instanceof StaticInitializer and
  // There must be an unsynchronized read.
  exists(IfStmt unsyncNullCheck | unsyncNullCheck = init.getAnEnclosingNullCheck() |
    not unsyncNullCheck.getEnclosingStmt+() instanceof ValidSynchStmt
  ) and
  if i.getEnclosingStmt+() instanceof ValidSynchStmt
  then (
    not init.getField().isVolatile() and
    message = "The field must be volatile."
  ) else (
    if i.getEnclosingStmt+() instanceof SynchronizedStmt
    then message = "Bad synchronization."
    else message = "Missing synchronization."
  )
select init, "Incorrect lazy initialization of static field $@: " + message, init.getField() as f,
  f.getName()

