/**
 * @name Low Java analysis quality
 * @description Low Java analysis quality
 * @kind diagnostic
 * @id java/diagnostic/database-quality
 */

import java
import DatabaseQuality

private predicate diagnostic(string msg, float value, float threshold) {
  CallTargetStatsReport::percentageOfOk(msg, value) and
  threshold = 85
  or
  ExprTypeStatsReport::percentageOfOk(msg, value) and
  threshold = 85
}

private newtype TDbQualityDiagnostic =
  TTheDbQualityDiagnostic() {
    exists(float percentageGood, float threshold |
      diagnostic(_, percentageGood, threshold) and
      percentageGood < threshold
    )
  }

private string getDbHealth() {
  result =
    strictconcat(string msg, float value, float threshold |
      diagnostic(msg, value, threshold)
    |
      msg + ": " + value.floor() + " % (threshold " + threshold.floor() + " %)", ". "
    )
}

class DbQualityDiagnostic extends TDbQualityDiagnostic {
  string toString() {
    result =
      "Scanning Java code completed successfully, but the scan encountered issues. " +
        "This may be caused by problems identifying dependencies or use of generated source code. " +
        "Some metrics of the database quality are: " + getDbHealth() + ". " +
        "Ideally these metrics should be above their thresholds. " +
        "Addressing these issues is advisable to avoid false-positives or missing results. If they cannot be addressed, consider scanning Java "
        +
        "using either the `autobuild` or `manual` [build modes](https://docs.github.com/en/code-security/code-scanning/creating-an-advanced-setup-for-code-scanning/codeql-code-scanning-for-compiled-languages#comparison-of-the-build-modes)."
  }
}

query predicate diagnosticAttributes(DbQualityDiagnostic e, string key, string value) {
  exists(e) and // Quieten warning about unconstrained 'e'
  key = ["visibilityCliSummaryTable", "visibilityTelemetry", "visibilityStatusPage"] and
  value = "true"
}

from DbQualityDiagnostic d
select d, d.toString(), 1
/* Warning severity */

Violations of Best Practice/Implementati:
/**
 * @name Cast from abstract to concrete collection
 * @description A cast from an abstract collection to a concrete implementation type makes the
 *              code brittle.
 * @kind problem
 * @problem.severity warning
 * @precision very-high
 * @id java/abstract-to-concrete-cast
 * @tags quality
 *       maintainability
 *       complexity
 *       modularity
 *       external/cwe/cwe-485
 */

import java
import semmle.code.java.Collections

predicate guardedByInstanceOf(VarAccess e, RefType t) {
  exists(Stmt s, InstanceOfExpr instanceCheck, RefType checkType |
    (
      s.(IfStmt).getCondition() = instanceCheck or
      s.(WhenBranch).getCondition() = instanceCheck
    ) and
    instanceCheck.getCheckedType() = checkType and
    // The same variable appears as the subject of the `instanceof`.
    instanceCheck.getExpr() = e.getVariable().getAnAccess() and
    // The checked type is either the type itself, or a raw version. For example, it is usually
    // fine to check for `x instanceof ArrayList` and then cast to `ArrayList<Foo>`, because
    // the generic parameter is usually known.
    (checkType = t or checkType = t.getSourceDeclaration().(GenericType).getRawType()) and
    // The expression appears in one of the branches.
    // (We do not verify here whether the guard is correctly implemented.)
    exists(Stmt branch |
      branch = s.(IfStmt).getThen() or
      branch = s.(IfStmt).getElse() or
      branch = s.(WhenBranch).getRhs()
    |
      branch = e.getEnclosingStmt().getEnclosingStmt+()
    )
  )
}

from CastingExpr e, CollectionType c, CollectionType coll, string abstractName, string concreteName
where
  coll instanceof Interface and
  c instanceof Class and
  // The result of the cast has type `c`.
  e.getType() = c and
  // The expression inside the cast has type `coll`.
  e.getExpr().getType() = coll and
  // The cast does not occur inside a check that the variable has that type.
  // In this case there is not really a break of abstraction, since it is not
  // *assumed* that the variable has that type. In practice, this usually corresponds
  // to a branch optimized for a specific subtype, and then a generic branch.
  not guardedByInstanceOf(e.getExpr(), c) and
  // Exclude results if "unchecked" warnings are deliberately suppressed.
  not e.getEnclosingCallable().suppressesWarningsAbout("unchecked") and
  // Report the qualified names if the names are the same.
  if coll.getName() = c.getName()
  then (
    abstractName = coll.getQualifiedName() and concreteName = c.getQualifiedName()
  ) else (
    abstractName = coll.getName() and concreteName = c.getName()
  )
select e, "$@ is cast to the concrete type $@, losing abstraction.", coll.getSourceDeclaration(),
  abstractName, c.getSourceDeclaration(), concreteName

/**
 * @name Exposing internal representation
 * @description An object that accidentally exposes its internal representation may allow the
 *              object's fields to be modified in ways that the object is not prepared to handle.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id java/internal-representation-exposure
 * @tags quality
 *       reliability
 *       correctness
 *       modularity
 *       external/cwe/cwe-485
 */

import java
import semmle.code.java.dataflow.DefUse

predicate relevantType(RefType t) {
  t instanceof Array
  or
  exists(RefType sup | sup = t.getAnAncestor().getSourceDeclaration() |
    sup.hasQualifiedName("java.util", "Map") or
    sup.hasQualifiedName("java.util", "Collection")
  )
}

predicate modifyMethod(Method m) {
  relevantType(m.getDeclaringType()) and
  (
    m.hasName("add") or
    m.hasName("addAll") or
    m.hasName("put") or
    m.hasName("putAll") or
    m.hasName("push") or
    m.hasName("pop") or
    m.hasName("remove") or
    m.hasName("removeAll") or
    m.hasName("clear") or
    m.hasName("set")
  )
}

predicate storesArray(Callable c, int i, Field f) {
  f.getDeclaringType() = c.getDeclaringType().getAnAncestor().getSourceDeclaration() and
  relevantType(f.getType()) and
  exists(Parameter p | p = c.getParameter(i) | f.getAnAssignedValue() = p.getAnAccess()) and
  not c.isStatic()
}

predicate returnsArray(Callable c, Field f) {
  f.getDeclaringType() = c.getDeclaringType().getAnAncestor().getSourceDeclaration() and
  relevantType(f.getType()) and
  exists(ReturnStmt rs | rs.getEnclosingCallable() = c and rs.getResult() = f.getAnAccess()) and
  not c.isStatic()
}

predicate mayWriteToArray(Expr modified) {
  writesToArray(modified)
  or
  // x = __y__; x[0] = 1;
  exists(AssignExpr e, LocalVariableDecl v | e.getDest() = v.getAnAccess() |
    modified = e.getSource() and
    mayWriteToArray(v.getAnAccess())
  )
  or
  // int[] x = __y__; x[0] = 1;
  exists(LocalVariableDeclExpr e, Variable v | e.getVariable() = v |
    modified = e.getInit() and
    mayWriteToArray(v.getAnAccess())
  )
  or
  // return __array__;    ...  method()[1] = 0
  exists(ReturnStmt rs | modified = rs.getResult() and relevantType(modified.getType()) |
    exists(Callable enclosing, MethodCall ma |
      enclosing = rs.getEnclosingCallable() and ma.getMethod().getSourceDeclaration() = enclosing
    |
      mayWriteToArray(ma)
    )
  )
}

predicate writesToArray(Expr array) {
  relevantType(array.getType()) and
  (
    exists(Assignment a, ArrayAccess access | a.getDest() = access | access.getArray() = array)
    or
    exists(MethodCall ma | ma.getQualifier() = array | modifyMethod(ma.getMethod()))
  )
}

VarAccess modificationAfter(VarAccess v) {
  mayWriteToArray(result) and
  useUsePair(v, result)
}

VarAccess varPassedInto(Callable c, int i) {
  exists(Call call | call.getCallee() = c | call.getArgument(i) = result)
}

predicate exposesByReturn(Callable c, Field f, Expr why, string whyText) {
  returnsArray(c, f) and
  exists(MethodCall ma |
    ma.getMethod().getSourceDeclaration() = c and ma.getCompilationUnit() != c.getCompilationUnit()
  |
    mayWriteToArray(ma) and
    why = ma and
    whyText = "after this call to " + c.getName()
  )
}

predicate exposesByStore(Callable c, Field f, Expr why, string whyText) {
  exists(VarAccess v, int i |
    storesArray(c, i, f) and
    v = varPassedInto(c, i) and
    v.getCompilationUnit() != c.getCompilationUnit() and
    why = modificationAfter(v) and
    whyText = "through the variable " + v.getVariable().getName()
  )
}

from Callable c, Field f, Expr why, string whyText
where
  (
    exposesByReturn(c, f, why, whyText) or
    exposesByStore(c, f, why, whyText)
  ) and
  // Kotlin properties expose internal representation, but it's not accidental, so ignore them
  not exists(Property p | p.getBackingField() = f)
select c,
  c.getName() + " exposes the internal representation stored in field " + f.getName() +
    ". The value may be modified $@.", why, whyText

/**
 * @id java/visible-for-testing-abuse
 * @name Use of VisibleForTesting in production code
 * @description Accessing methods, fields or classes annotated with `@VisibleForTesting` from
 *              production code goes against the intention of the annotation and may indicate
 *              programmer error.
 * @kind problem
 * @precision high
 * @problem.severity warning
 * @tags quality
 *       maintainability
 *       readability
 */

import java

/**
 * Holds if a `Callable` is within the same type hierarchy as `RefType`
 * (including through lambdas, inner classes, and outer classes).
 */
predicate isWithinType(Callable c, RefType t) {
  // Either the callable is in the target type, or they share a common enclosing type
  c.getDeclaringType().getEnclosingType*() = t.getEnclosingType*()
}

/**
 * Holds if `e` is within the same package as `t`.
 */
predicate isWithinPackage(Expr e, RefType t) {
  e.getCompilationUnit().getPackage() = t.getPackage()
}

/**
 * Holds if a callable or any of its enclosing callables is annotated with @VisibleForTesting.
 */
predicate isWithinVisibleForTestingContext(Callable c) {
  c.getAnAnnotation().getType().hasName("VisibleForTesting")
  or
  isWithinVisibleForTestingContext(c.getEnclosingCallable())
}

/**
 * Holds if `e` is within a test method context, including lambda expressions
 * within test methods and nested lambdas.
 */
private predicate isWithinTest(Expr e) {
  e.getEnclosingCallable() instanceof LikelyTestMethod
  or
  exists(Method lambda, LambdaExpr lambdaExpr |
    lambda = lambdaExpr.asMethod() and
    lambda.getEnclosingCallable*() instanceof LikelyTestMethod and
    e.getEnclosingCallable() = lambda
  )
}

from Annotatable annotated, Expr e
where
  annotated.getAnAnnotation().getType().hasName("VisibleForTesting") and
  (
    // field access
    e =
      any(FieldAccess v |
        v.getField() = annotated and
        // depending on the visibility of the field, using the annotation to abuse the visibility may/may not be occurring
        (
          // if its package protected report when its used outside its class because it should have been private (class only permitted)
          v.getField().isPackageProtected() and
          not isWithinType(v.getEnclosingCallable(), v.getField().getDeclaringType())
          or
          // if public or protected report when its used outside its package because package protected should have been enough (package only permitted)
          (v.getField().isPublic() or v.getField().isProtected()) and
          not isWithinPackage(v, v.getField().getDeclaringType())
        )
      )
    or
    // method access
    e =
      any(MethodCall c |
        c.getMethod() = annotated and
        // depending on the visibility of the method, using the annotation to abuse the visibility may/may not be occurring
        (
          // if its package protected report when its used outside its class because it should have been private (class only permitted)
          c.getMethod().isPackageProtected() and
          not isWithinType(c.getEnclosingCallable(), c.getMethod().getDeclaringType())
          or
          // if public or protected report when its used outside its package because package protected should have been enough (package only permitted)
          (c.getMethod().isPublic() or c.getMethod().isProtected()) and
          not isWithinPackage(c, c.getMethod().getDeclaringType())
        )
      )
    or
    // Class instantiation - report if used outside appropriate scope
    e =
      any(ClassInstanceExpr c |
        c.getConstructedType() = annotated and
        (
          c.getConstructedType().isPublic() and not isWithinPackage(c, c.getConstructedType())
          or
          c.getConstructedType().hasNoModifier() and
          c.getConstructedType() instanceof NestedClass and
          not isWithinType(c.getEnclosingCallable(), c.getConstructedType())
        )
      )
  ) and
  // not in a test where use is appropriate
  not isWithinTest(e) and
  // not when the accessing method or any enclosing method is @VisibleForTesting (test-to-test communication)
  not isWithinVisibleForTestingContext(e.getEnclosingCallable()) and
  // not when used in annotation contexts
  not e.getParent*() instanceof Annotation
select e, "Access of $@ annotated with VisibleForTesting found in production code.", annotated,
  "element"

Violations of Best Practice/SpecialChara:
/**
 * @id java/non-explicit-control-and-whitespace-chars-in-literals
 * @name Non-explicit control and whitespace characters
 * @description Non-explicit control and whitespace characters in literals make code more difficult
 *              to read and may lead to incorrect program behavior.
 * @kind problem
 * @precision very-high
 * @problem.severity warning
 * @tags quality
 *       correctness
 *       maintainability
 *       readability
 */

import java

/**
 * A `Literal` that has a Unicode control character within its
 * literal value (as returned by `getLiteral()` member predicate).
 */
class ReservedUnicodeInLiteral extends Literal {
  private int indexStart;

  ReservedUnicodeInLiteral() {
    not this instanceof CharacterLiteral and
    this.getCompilationUnit().fromSource() and
    exists(int codePoint |
      this.getLiteral().codePointAt(indexStart) = codePoint and
      (
        // Unicode C0 control characters
        codePoint < 32 and not codePoint in [9, 10, 12, 13]
        or
        codePoint = 127 // delete control character
        or
        codePoint = 8203 // zero-width space
      )
    )
  }

  /** Gets the starting index of the Unicode control sequence. */
  int getIndexStart() { result = indexStart }
}

from ReservedUnicodeInLiteral literal, int charIndex, int codePoint
where
  literal.getIndexStart() = charIndex and
  literal.getLiteral().codePointAt(charIndex) = codePoint and
  not literal.getEnclosingCallable() instanceof LikelyTestMethod and
  // Kotlin extraction doesn't preserve the literal value so we can't distinguish
  // between control characters and their escaped versions, so we exclude Kotlin
  // to avoid false positives.
  not literal.getFile().isKotlinSourceFile()
select literal,
  "Literal value contains control or non-printable whitespace character(s) starting with Unicode code point "
    + codePoint + " at index " + charIndex + "."

Violations of Best Practice/Naming Conve:
/**
 * @name Confusing overloading of methods
 * @description Overloaded methods that have the same number of parameters, where each pair of
 *              corresponding parameter types is convertible by casting or autoboxing, may be
 *              confusing.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id java/confusing-method-signature
 * @tags quality
 *       maintainability
 *       readability
 *       naming
 */

import java

pragma[nomagic]
private predicate confusingPrimitiveBoxedTypes(Type t, Type u) {
  t.(PrimitiveType).getBoxedType() = u or
  u.(PrimitiveType).getBoxedType() = t
}

private predicate overloadedMethods(Method n, Method m) {
  n.fromSource() and
  exists(RefType rt, string name, int numParams |
    candidateMethod(rt, m, name, numParams) and
    candidateMethod(rt, n, name, numParams)
  ) and
  n != m and
  n.getSourceDeclaration().getSignature() < m.getSourceDeclaration().getSignature()
}

private predicate overloadedMethodsMostSpecific(Method n, Method m) {
  overloadedMethods(n, m) and
  not exists(Method nSup, Method mSup |
    n.overridesOrInstantiates*(nSup) and m.overridesOrInstantiates*(mSup)
  |
    overloadedMethods(nSup, mSup) and
    (n != nSup or m != mSup)
  )
}

/**
 * A whitelist of names that are commonly overloaded in odd ways and should
 * not be reported by this query.
 */
private predicate whitelist(string name) { name = "visit" }

/**
 * Method `m` has name `name`, number of parameters `numParam`
 * and is declared in `t` or inherited from a supertype of `t`.
 */
pragma[nomagic]
private predicate candidateMethod(RefType t, Method m, string name, int numParam) {
  exists(Method n | n.getSourceDeclaration() = m | t.inherits(n)) and
  m.getName() = name and
  m.getNumberOfParameters() = numParam and
  m = m.getSourceDeclaration() and
  not m.getAnAnnotation() instanceof DeprecatedAnnotation and
  // Exclude compiler generated methods, such as Kotlin `$default` methods:
  not m.isCompilerGenerated() and
  not whitelist(name)
}

predicate paramTypePair(Type t1, Type t2) {
  exists(Method n, Method m, int i |
    overloadedMethodsMostSpecific(n, m) and
    t1 = n.getParameterType(pragma[only_bind_into](i)) and
    t2 = m.getParameterType(pragma[only_bind_into](i))
  )
}

// handle simple cases separately
predicate potentiallyConfusingTypesSimple(Type t1, Type t2) {
  paramTypePair(t1, t2) and
  (
    t1 = t2
    or
    t1 instanceof TypeObject and t2 instanceof RefType
    or
    t2 instanceof TypeObject and t1 instanceof RefType
    or
    confusingPrimitiveBoxedTypes(t1, t2)
  )
}

// check erased types first
predicate potentiallyConfusingTypesRefTypes(RefType t1, RefType t2) {
  paramTypePair(t1, t2) and
  not potentiallyConfusingTypesSimple(t1, t2) and
  haveIntersection(t1, t2)
}

// then check hasSubtypeOrInstantiation
pragma[nomagic]
predicate potentiallyConfusingTypes(Type t1, Type t2) {
  potentiallyConfusingTypesSimple(t1, t2)
  or
  potentiallyConfusingTypesRefTypes(t1, t2) and
  exists(RefType commonSubtype | hasSubtypeOrInstantiation*(t1, commonSubtype) |
    hasSubtypeOrInstantiation*(t2, commonSubtype)
  )
}

private predicate hasSubtypeOrInstantiation(RefType t, RefType sub) {
  hasSubtype(t, sub) or
  sub.getSourceDeclaration() = t
}

private predicate confusinglyOverloaded(Method m, Method n) {
  overloadedMethodsMostSpecific(n, m) and
  forall(int i, Parameter p, Parameter q | p = n.getParameter(i) and q = m.getParameter(i) |
    potentiallyConfusingTypes(p.getType(), q.getType())
  ) and
  // There is no possibility for confusion between two methods with identical behavior.
  not exists(Method target | delegate*(m, target) and delegate*(n, target))
}

private predicate wrappedAccess(Expr e, MethodCall ma) {
  e = ma or
  wrappedAccess(e.(CastingExpr).getExpr(), ma)
}

private predicate delegate(Method caller, Method callee) {
  exists(MethodCall ma | ma.getMethod() = callee |
    exists(Stmt stmt | stmt = caller.getBody().(SingletonBlock).getStmt() |
      wrappedAccess(stmt.(ExprStmt).getExpr(), ma) or
      wrappedAccess(stmt.(ReturnStmt).getResult(), ma)
    ) and
    forex(Parameter p, int i, Expr arg | p = caller.getParameter(i) and ma.getArgument(i) = arg |
      // The parameter is propagated without modification.
      arg = p.getAnAccess()
      or
      // The parameter is cast to a supertype.
      arg.(CastingExpr).getExpr() = p.getAnAccess() and
      arg.getType().(RefType).getASubtype() = p.getType()
    )
  )
}

from Method m, Method n, string messageQualifier
where
  confusinglyOverloaded(m, n) and
  (
    if m.getDeclaringType() = n.getDeclaringType()
    then messageQualifier = ""
    else messageQualifier = m.getDeclaringType().getName() + "."
  )
select n,
  "Method " + n.getDeclaringType() + "." + n +
    "(..) could be confused with overloaded method $@, since dispatch depends on static types.",
  m.getSourceDeclaration(), messageQualifier + m.getName()

Violations of Best Practice/Undesirable:
/**
 * @name Forcible JVM termination
 * @description Calling 'System.exit', 'Runtime.halt', or 'Runtime.exit' may make code harder to
 *              reuse and prevent important cleanup steps from running.
 * @kind problem
 * @problem.severity warning
 * @precision medium
 * @id java/jvm-exit
 * @previous-id java/jvm-exit-prevents-cleanup-and-reuse
 * @tags quality
 *       reliability
 *       correctness
 *       external/cwe/cwe-382
 */

import java

/**
 * A `Method` which, when called, causes the JVM to exit or halt.
 *
 * Explicitly includes these methods from the java standard library:
 *   - `java.lang.System.exit`
 *   - `java.lang.Runtime.halt`
 *   - `java.lang.Runtime.exit`
 */
class ExitOrHaltMethod extends Method {
  ExitOrHaltMethod() {
    exists(Class system | this.getDeclaringType() = system |
      this.hasName("exit") and
      system.hasQualifiedName("java.lang", ["System", "Runtime"])
      or
      this.hasName("halt") and
      system.hasQualifiedName("java.lang", "Runtime")
    )
  }
}

/** A `MethodCall` to an `ExitOrHaltMethod`, which causes the JVM to exit abruptly. */
class ExitOrHaltMethodCall extends MethodCall {
  ExitOrHaltMethodCall() {
    exists(ExitOrHaltMethod exitMethod | this.getMethod() = exitMethod |
      exists(SourceMethodNotMainOrTest srcMethod | this = srcMethod.getACallSite(exitMethod))
    )
  }
}

/**
 * An intentional `MethodCall` to a system or runtime "exit" method, such as for
 * functions which exist for the purpose of exiting the program. Assumes that an exit method
 * call within a method is intentional if the exit code is passed from a parameter of the
 * enclosing method.
 */
class IntentionalExitMethodCall extends ExitOrHaltMethodCall {
  IntentionalExitMethodCall() {
    this.getMethod().hasName("exit") and
    this.getAnArgument() = this.getEnclosingCallable().getAParameter().getAnAccess()
  }
}

/**
 * A `Method` that is defined in source code and is not a `MainMethod` or a `LikelyTestMethod`.
 */
class SourceMethodNotMainOrTest extends Method {
  SourceMethodNotMainOrTest() {
    this.fromSource() and
    not this instanceof MainMethod and
    not (
      this.getEnclosingCallable*() instanceof LikelyTestMethod
      or
      this.getDeclaringType()
          .getEnclosingType*()
          .(LocalClassOrInterface)
          .getLocalTypeDeclStmt()
          .getEnclosingCallable() instanceof LikelyTestMethod
    )
  }
}

from ExitOrHaltMethodCall mc
where not mc instanceof IntentionalExitMethodCall
select mc,
  "Avoid calls to " + mc.getMethod().getDeclaringType().getName() + "." + mc.getMethod().getName() +
    "() as this prevents runtime cleanup and makes code harder to reuse."

Violations of Best Practice/legacy/AutoB:
/**
 * @name Auto boxing or unboxing
 * @description Implicit boxing or unboxing of primitive types, such as 'int' and 'double',
 *              may cause confusion and subtle performance problems.
 * @kind problem
 * @problem.severity warning
 * @precision low
 * @id java/implicit-auto-boxing
 * @tags efficiency
 */

import java

/** An expression of primitive type. */
class PrimitiveExpr extends Expr {
  PrimitiveExpr() { this.getType() instanceof PrimitiveType }
}

/** An expression of boxed type. */
class BoxedExpr extends Expr {
  BoxedExpr() { this.getType() instanceof BoxedType }
}

/**
 * Relate expressions and the variables they flow into in one step,
 * either by assignment or parameter passing.
 */
Variable flowTarget(Expr arg) {
  arg = result.getAnAssignedValue()
  or
  exists(Call c, int i | c.getArgument(i) = arg and result = c.getCallee().getParameter(i))
}

/**
 * Holds if `e` is in a syntactic position where it is implicitly unboxed.
 */
predicate unboxed(BoxedExpr e) {
  exists(BinaryExpr bin | e = bin.getAnOperand() |
    if bin instanceof EqualityTest or bin instanceof ComparisonExpr
    then bin.getAnOperand() instanceof PrimitiveExpr
    else bin instanceof PrimitiveExpr
  )
  or
  exists(Assignment assign | assign.getDest() instanceof PrimitiveExpr | assign.getSource() = e)
  or
  flowTarget(e).getType() instanceof PrimitiveType
  or
  exists(ConditionalExpr cond | cond instanceof PrimitiveExpr | cond.getABranchExpr() = e)
}

/**
 * Holds if `e` is in a syntactic position where it is implicitly boxed.
 */
predicate boxed(PrimitiveExpr e) {
  exists(AssignExpr assign | assign.getDest() instanceof BoxedExpr | assign.getSource() = e)
  or
  flowTarget(e).getType() instanceof BoxedType
  or
  exists(ConditionalExpr cond | cond instanceof BoxedExpr |
    cond.getTrueExpr() = e or cond.getFalseExpr() = e
  )
}

/**
 * Holds if `e` is an assignment that unboxes, updates and reboxes `v`.
 */
predicate rebox(Assignment e, Variable v) {
  v.getType() instanceof BoxedType and
  not e instanceof AssignExpr and
  e.getDest() = v.getAnAccess()
}

from Expr e, string conv
where
  e.getFile().isJavaSourceFile() and
  (
    boxed(e) and conv = "This expression is implicitly boxed."
    or
    unboxed(e) and conv = "This expression is implicitly unboxed."
    or
    exists(Variable v | rebox(e, v) |
      conv =
        "This expression implicitly unboxes, updates, and reboxes the value of '" + v.getName() +
          "'."
    )
  )
select e, conv

Violations of Best Practice/Testing/Exce:
/**
 * @id java/excessive-public-method-mocking
 * @previous-id java/mocking-all-non-private-methods-means-unit-test-is-too-big
 * @name Mocking all public methods of a class may indicate the unit test is testing too much
 * @description Mocking all public methods provided by a class might indicate the unit test
 *              aims to test too many things.
 * @kind problem
 * @precision high
 * @problem.severity recommendation
 * @tags quality
 *       maintainability
 *       readability
 */

import java

/**
 * A call to Mockito's `mock` method.
 */
class MockitoMockCall extends MethodCall {
  MockitoMockCall() { this.getMethod().hasQualifiedName("org.mockito", "Mockito", "mock") }

  /**
   * Gets the type that this call intends to mock. For example:
   * ```java
   * EmployeeRecord employeeRecordMock = mock(EmployeeRecord.class);
   * ```
   * This predicate gets the class `EmployeeRecord` in the above example.
   */
  Type getMockedType() { result = this.getAnArgument().(TypeLiteral).getReferencedType() }
}

/**
 * A method call that mocks a target method in a JUnit test. For example:
 * ```java
 * EmployeeRecord employeeRecordMock = mock(EmployeeRecord.class);
 * when(employeeRecordMock.add(sampleEmployee)).thenReturn(0); // Mocked EmployeeRecord.add
 * doReturn(0).when(employeeRecordMock).add(sampleEmployee);   // Mocked EmployeeRecord.add
 * ```
 * This class captures the call to `add` which mocks the equivalent method of the class `EmployeeRecord`.
 */
class MockitoMockingMethodCall extends MethodCall {
  MockitoMockCall mockCall;

  MockitoMockingMethodCall() {
    /* 1. The qualifier originates from the mock call. */
    this.getQualifier().getControlFlowNode().getAPredecessor+() = mockCall.getControlFlowNode() and
    /* 2. The mocked method can be found in the class being mocked with the mock call. */
    mockCall.getMockedType().(ClassOrInterface).getAMethod() = this.getMethod()
  }

  /**
   * Gets the call to Mockito's `mock` from which the qualifier, the mocked object, originates.
   */
  MockitoMockCall getMockitoMockCall() { result = mockCall }
}

/*
 * The following from-where-select embodies this pseudocode:
 * - Find a JUnit4TestMethod which:
 *   - for a class that it mocks with a call to `mock`,
 *     - for all methods that the class has, there is a method that this test method mocks.
 */

from JUnit4TestMethod testMethod, ClassOrInterface mockedClassOrInterface
where
  exists(MockitoMockCall mockCall |
    mockCall.getEnclosingCallable() = testMethod and
    mockedClassOrInterface = mockCall.getMockedType() and
    // Only flag classes with multiple public methods (2 or more)
    strictcount(Method m | m = mockedClassOrInterface.getAMethod() and m.isPublic()) > 1 and
    forex(Method method | method = mockedClassOrInterface.getAMethod() and method.isPublic() |
      exists(MockitoMockingMethodCall mockedMethod |
        mockedMethod.getMockitoMockCall() = mockCall and
        mockedMethod.getMethod() = method
      )
    )
  )
select testMethod, "This test method mocks all public methods of a $@.", mockedClassOrInterface,
  "class or an interface"

Violations of Best Practice/Dead Code/De:
/**
 * @name Unused classes and interfaces
 * @description A non-public class or interface that is not used anywhere in the program wastes
 *              programmer resources.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id java/unused-reference-type
 * @tags quality
 *       maintainability
 *       useless-code
 *       external/cwe/cwe-561
 */

import java
import semmle.code.java.Reflection

/**
 * Gets a transitive superType avoiding magic optimisation
 */
pragma[nomagic]
cached
private RefType getASuperTypePlus(RefType t) { hasDescendant(result, t) and result != t }

/**
 * A class or interface that is not used anywhere.
 */
predicate dead(RefType dead) {
  dead.fromSource() and
  // Nothing depends on this type.
  not exists(RefType s | s.getMetrics().getADependency() = dead) and
  // Exclude Struts or JSP classes (marked with Javadoc tags).
  not exists(JavadocTag tag, string x |
    tag = dead.getDoc().getJavadoc().getATag(x) and
    (x.matches("@struts%") or x.matches("@jsp%"))
  ) and
  // Exclude public types.
  not dead.isPublic() and
  // Exclude results that have a `main` method.
  not dead.getAMethod().hasName("main") and
  // Exclude results that are referenced in XML files.
  not exists(XmlAttribute xla | xla.getValue() = dead.getQualifiedName()) and
  // Exclude type variables.
  not dead instanceof BoundedType and
  // Exclude JUnit tests.
  not dead.getAnAncestor().hasName("TestCase") and
  // Exclude enum types.
  not dead instanceof EnumType and
  // Exclude anonymous classes
  not dead instanceof AnonymousClass and
  // Exclude classes that look like they may be reflectively constructed.
  not dead.getAnAnnotation() instanceof ReflectiveAccessAnnotation and
  not dead.getAMethod().getAnAnnotation() instanceof ReflectiveAccessAnnotation and
  // Insist all source ancestors are dead as well.
  forall(RefType t | t.fromSource() and t = getASuperTypePlus(dead) | dead(t)) and
  // Exclude compiler generated classes (e.g. declaring type of adapter functions in Kotlin)
  not dead.isCompilerGenerated()
}

from RefType t, string kind
where
  dead(t) and
  (
    t instanceof Class and kind = "class"
    or
    t instanceof Interface and kind = "interface"
  )
select t,
  "Unused " + kind + ": " + t.getName() + " is not referenced within this codebase. " +
    "If not used as an external API it should be removed."
